import{_ as e,o as t,c as r,a2 as _}from"./chunks/framework.DnrXFDHb.js";const p=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"審計報告庫/經營審計/6903_巨漢/20260502/G08_區域銷售分佈與地緣風險_企業風險評估專家.md","filePath":"審計報告庫/經營審計/6903_巨漢/20260502/G08_區域銷售分佈與地緣風險_企業風險評估專家.md"}'),o={name:"審計報告庫/經營審計/6903_巨漢/20260502/G08_區域銷售分佈與地緣風險_企業風險評估專家.md"};function i(l,a,n,s,h,d){return t(),r("div",null,[...a[0]||(a[0]=[_('<h2 id="📋-審計題目" tabindex="-1">📋 審計題目 <a class="header-anchor" href="#📋-審計題目" aria-label="Permalink to &quot;📋 審計題目&quot;">​</a></h2><p>區域銷售分佈與地緣風險</p><h2 id="🎯-專家直斷" tabindex="-1">🎯 專家直斷 <a class="header-anchor" href="#🎯-專家直斷" aria-label="Permalink to &quot;🎯 專家直斷&quot;">​</a></h2><p>巨漢營收 100% 來自台灣（半導體廠房統包），無海外營收。若台海地緣政治升溫或半導體供應鏈移轉，將直接衝擊營收且無海外緩衝。海外布局已宣布但無具體進度，區域集中風險短期無法分散。</p><h2 id="📊-診斷評級" tabindex="-1">📊 診斷評級 <a class="header-anchor" href="#📊-診斷評級" aria-label="Permalink to &quot;📊 診斷評級&quot;">​</a></h2><p>B（持平）。客戶品質優良，但區域集中度過高。利空：若兩岸關係緊張，外資可能撤離台灣半導體供應鏈，巨漢將首當其衝。公司雖宣布赴美設分公司但無具體時程，海外布局緩慢將加劇風險。公共工程業務雖有助分散但毛利率較低，恐進一步壓縮獲利空間。</p><h2 id="🔍-答詢詳解" tabindex="-1">🔍 答詢詳解 <a class="header-anchor" href="#🔍-答詢詳解" aria-label="Permalink to &quot;🔍 答詢詳解&quot;">​</a></h2><p>巨漢業務全部在台灣，主要服務新竹、苗栗、台南科學園區的半導體客戶。無海外子公司，無外幣營收。2025 年營收 31.77 億中 99%+ 來自台灣半導體廠房統包工程。已宣布赴美設分公司計畫（跟隨台積電等客戶海外設廠需求），但截至最近期財報尚未揭露具體時程和資本支出金額。短期內營收區域集中風險無法分散，公司成長完全依賴台灣半導體資本支出景氣。因無海外營收，新台幣匯率變動對營運無影響。</p><h2 id="💡-專家評析" tabindex="-1">💡 專家評析 <a class="header-anchor" href="#💡-專家評析" aria-label="Permalink to &quot;💡 專家評析&quot;">​</a></h2><ol><li><strong>地緣政治風險不可忽視</strong>：營收 100% 集中台灣半導體產業是結構性風險。若兩岸關係持續緊張，外資可能降低台灣半導體供應鏈曝險，巨漢作為本地統包商將直接受衝擊，訂單流失壓力巨大。</li><li><strong>海外布局進度不明風險</strong>：赴美設分公司已宣布但無具體時程，海外營收短期內貢獻有限。若不加快海外布局，將錯過半導體客戶海外設廠的統包商機。</li><li><strong>區域集中 vs 獲利權衡的壓力</strong>：拓展公共工程可分散風險，但公共工程毛利率通常低於半導體廠務案，可能進一步壓縮整體獲利，形成兩難。</li></ol><h2 id="📚-證據來源" tabindex="-1">📚 證據來源 <a class="header-anchor" href="#📚-證據來源" aria-label="Permalink to &quot;📚 證據來源&quot;">​</a></h2><p>web_search：巨漢業務概況、海外布局</p>',12)])])}const u=e(o,[["render",i]]);export{p as __pageData,u as default};
